// named import;必须传 shadow 内真实元素(字符串 selector 按 document 解析,看不到 shadow)
import { PowerGlitch } from 'https://cdn.jsdelivr.net/npm/powerglitch@2.5.0/+esm';
const el = document.createElement('div'); el.style.display = 'inline-block'; el.textContent = data.text ?? 'GLITCH'; shadowRoot.appendChild(el);
PowerGlitch.glitch(el, data.options ?? {}); // 原位包两层容器 + WAAPI,无样式外泄

